function currentQuiz(){const doc=getActiveDoc(),summary=activeModule>0?doc.title:lessonSummaries[activeLesson],facts=activeModule===0&&activeLesson===0?quiz.slice(0,4).map(x=>[x.q,x.options[x.answer],x.options.filter((_,i)=>i!==x.answer)]):activeModule===5?advancedFinanceFacts[activeLesson]:activeModule===4?accountingFacts[activeLesson]:activeModule===3?businessFacts[activeLesson]:activeModule===2?investingFacts[activeLesson]:activeModule===1?personalFacts[activeLesson]:lessonFacts[activeLesson];return Array.from({length:12},(_,i)=>{const band=Math.floor(i/4),f=facts[i%4],level=["EASY","MEDIUM","HARD"][band],q=band===0?f[0]:band===1?`Which answer best explains how this ${summary} concept works in practice: ${f[0]}`:`A decision-maker faces a real situation involving ${summary}. Before acting, they must correctly apply the lesson behind "${f[0]}" Which conclusion would lead to the most financially sound decision?`,options=[f[1],...f[2]],shift=(i*3)%4;return {q,options:[...options.slice(shift),...options.slice(0,shift)],answer:(4-shift)%4,why:`${f[1]} is correct. ${band===0?"It states the core definition clearly.":band===1?"It connects the lesson concept to how financial decisions work in practice.":"It applies the lesson principle while avoiding the misleading alternatives, which is essential in real financial analysis."}`,level}})}

let state = JSON.parse(localStorage.getItem("finteenState") || "null") || { user:null, completedLessons:[], quizzes:[] };
let accounts = JSON.parse(localStorage.getItem("finteenAccounts") || "{}");
let learnerCount = Number(localStorage.getItem("finteenLearnerCount") || 0);
let currentView="dashboard", activeModule=null, activeLesson=null, activeCareer=null, quizIndex=0, quizScore=0;
const container=document.getElementById("view-container"), title=document.getElementById("page-title");
const profileKey=username=>username.trim().toLowerCase().replace(/\s+/g," ");
const hashPassword=password=>{let hash=2166136261;for(const ch of password){hash^=ch.charCodeAt(0);hash=Math.imul(hash,16777619)}return (hash>>>0).toString(36)};
const save=()=>{localStorage.setItem("finteenState",JSON.stringify(state));if(state.user){accounts[profileKey(state.user.name)]=state;localStorage.setItem("finteenAccounts",JSON.stringify(accounts))}};
const initials=()=>state.user?.name.split(/\s+/).map(x=>x[0]).slice(0,2).join("").toUpperCase()||"FT";
const money=v=>new Intl.NumberFormat("en-IN",{style:"currency",currency:"INR",maximumFractionDigits:0}).format(v);
const pageHead=(e,h,c)=>`<div class="page-head"><div><p class="eyebrow">${e}</p><h1>${h}</h1><p class="subtitle">${c}</p></div></div>`;
function markdownToHtml(md){const inline=s=>s.replace(/\*\*(.+?)\*\*/g,"<strong>$1</strong>");let html="",list=null;for(const raw of md.split("\n")){const line=raw.trim();if(!line){if(list){html+=`</${list}>`;list=null}continue}if(line==="---"){if(list){html+=`</${list}>`;list=null}html+="<hr>";continue}const bullet=line.match(/^\*\s+(.+)/),number=line.match(/^\d+\.\s+(.+)/),heading=line.match(/^#{1,6}\s+(.+)/);if(bullet||number){const type=bullet?"ul":"ol";if(list!==type){if(list)html+=`</${list}>`;html+=`<${type}>`;list=type}html+=`<li>${inline((bullet||number)[1])}</li>`;continue}if(list){html+=`</${list}>`;list=null}if(heading)html+=`<h2>${inline(heading[1])}</h2>`;else html+=`<p>${inline(line)}</p>`}if(list)html+=`</${list}>`;return html}
function updateLearnerCount(){const el=document.querySelector("#learner-count strong");if(el)el.textContent=learnerCount.toLocaleString("en-IN")}

function onboarding(){
  document.body.insertAdjacentHTML("beforeend",`<div class="onboarding" id="onboarding"><section class="card onboarding-card"><img class="onboarding-logo" src="assets/finteen-logo.png" alt="FinTeen"><p class="eyebrow">Your financial journey starts here</p><h1>Enter your username and password</h1><p class="subtitle">Use the same username and password later to continue exactly where you left off.</p><form id="register-form"><div class="input-group"><label>Username</label><input id="reg-name" required autocomplete="username" placeholder="Enter your username"></div><div class="input-group"><label>Password</label><input id="reg-password" type="password" required autocomplete="current-password" placeholder="Enter your password"></div><p class="form-error" id="form-error"></p><button class="button primary full">Log In to FinTeen AI</button></form></section></div>`);
  document.getElementById("register-form").addEventListener("submit",e=>{e.preventDefault();const name=document.getElementById("reg-name").value.trim(),password=document.getElementById("reg-password").value,passwordHash=hashPassword(password),key=profileKey(name),existing=accounts[key],error=document.getElementById("form-error");if(name.length<2){error.textContent="Please enter a username with at least 2 characters.";return}if(password.length<4){error.textContent="Please enter a password with at least 4 characters.";return}if(existing?.user?.passwordHash&&existing.user.passwordHash!==passwordHash||existing?.user?.password&&existing.user.password!==password){error.textContent="Incorrect password for this username.";return}state=existing||{user:{name,passwordHash},completedLessons:[],quizzes:[]};state.user={name,passwordHash};learnerCount++;localStorage.setItem("finteenLearnerCount",learnerCount);save();document.getElementById("onboarding").remove();syncUser();navigate("dashboard");});
}
function syncUser(){document.querySelectorAll(".avatar").forEach(x=>x.textContent=initials());document.querySelector(".sidebar-footer strong").textContent=state.user?.name||"New learner";document.querySelector(".sidebar-footer small").textContent=state.completedLessons.length?"Learning in progress":"New learner";document.querySelectorAll(".progress-only").forEach(x=>x.classList.toggle("hidden",!state.completedLessons.length&&!state.quizzes.length));const orbit=document.querySelector(".mini-orbit"),weekly=document.querySelector(".sidebar-card p");if(orbit)orbit.textContent=state.completedLessons.length;if(weekly)weekly.innerHTML=`<strong>Lessons complete</strong><br><span>${state.completedLessons.length} topic${state.completedLessons.length===1?"":"s"} learned</span>`;updateLearnerCount()}
function signOut(){save();state={user:null,completedLessons:[],quizzes:[]};localStorage.removeItem("finteenState");document.querySelector(".account-menu")?.remove();syncUser();container.innerHTML="";onboarding()}
function toggleAccountMenu(){const old=document.querySelector(".account-menu");if(old){old.remove();return}document.querySelector(".sidebar-footer").insertAdjacentHTML("beforeend",`<div class="account-menu"><button id="sign-out">Sign Out</button></div>`);document.getElementById("sign-out").onclick=signOut}
function renderDashboard(){
  const has=state.completedLessons.length||state.quizzes.length, learned=new Set(state.completedLessons.map(x=>x.split("-")[0])).size, accuracy=state.quizzes.length?Math.round(state.quizzes.reduce((a,b)=>a+b.score,0)/(state.quizzes.length*12)*100):0, progress=Math.round(state.completedLessons.length/modules.reduce((a,m)=>a+m.lessons.length,0)*100),nextIndex=modules.findIndex((m,i)=>state.completedLessons.filter(x=>x.startsWith(i+"-")).length<m.lessons.length),targetIndex=nextIndex<0?modules.length-1:nextIndex,target=modules[targetIndex],targetDone=state.completedLessons.filter(x=>x.startsWith(targetIndex+"-")).length,targetComplete=nextIndex<0;
  if(!has)return `${pageHead(`Welcome, ${state.user.name.split(" ")[0]}`,"Start your financial learning journey.","Your account is ready. Begin with Money Fundamentals and earn progress as you learn.")}<section class="card journey-card"><div class="insight-icon">↗</div><h2>One lesson is all it takes to begin.</h2><p class="subtitle" style="margin:10px auto 20px">Read your first financial lesson, mark it complete, then unlock its quiz.</p><button class="button primary" data-module="0">Explore Money Fundamentals →</button></section>`;
  return `${pageHead(`Welcome back, ${state.user.name.split(" ")[0]}`,"Keep building your money confidence.","Every completed lesson adds to your financial toolkit.")}
  <div class="grid progress-overview">${[["Lessons Completed",state.completedLessons.length],["Quizzes Completed",state.quizzes.length],["Quiz Accuracy",accuracy+"%"],["Topics Learned",learned],["Learning Progress",progress+"%"],["Current Learning Path",targetComplete?"All Modules Complete":`Module ${targetIndex+1}`]].map(x=>`<div class="card stat-card"><div class="stat-icon">✓</div><div><strong>${x[1]}</strong><span>${x[0]}</span></div></div>`).join("")}</div>
  <div class="section-head"><h2>${targetComplete?"Learning journey complete":"Continue learning"}</h2></div><section class="card hero-card"><p class="eyebrow">Module ${targetIndex+1} · ${target.title}</p><h2>${targetComplete?"You completed every FinTeen module":`Continue with Module ${targetIndex+1}`}</h2><p>${targetComplete?"Review any module to keep your financial knowledge sharp.":"Continue the next module in your learning path and unlock its quizzes."}</p><button class="button" data-module="${targetIndex}">${targetComplete?"Review modules":"Continue learning"} →</button><div class="hero-meta"><div class="progress-track"><div class="progress-fill" style="width:${targetDone/target.lessons.length*100}%"></div></div><span>${targetDone}/${target.lessons.length} lessons</span></div></section>`;
}
