function renderSimulator(){return `${pageHead("Budget Lab","Build a budget that fits your priorities","Set a goal, then adjust every monthly category to see the real trade-offs and timeline.")}
<div class="grid sim-layout"><section class="card form-card"><div class="input-group"><label>Your age</label><input id="age" type="number" min="13" max="18" value="16"></div><div class="input-group"><label>Monthly income</label><input id="income" type="number" value="10000"></div><div class="input-group"><label>Goal amount</label><input id="goalAmount" type="number" value="60000"></div><label style="font-size:10px;font-weight:800">CHOOSE A GOAL</label><div class="goal-pills">${["New Phone","Laptop","College Fund","Gaming Setup","Bicycle","Vacation","Emergency Fund","Custom Goal"].map((x,i)=>`<button class="goal-pill ${i===1?"active":""}">${x}</button>`).join("")}</div><div class="input-group custom-goal"><label>Your custom goal</label><input id="customGoal" placeholder="What are you saving for?"></div><button class="button primary full" id="run-sim">Build adjustable budget</button></section><section class="card result-card" id="sim-result"><div class="empty-state"><div><span>◫</span><h2>Your adjustable plan will appear here</h2><p class="subtitle">You control how every rupee is allocated.</p></div></div></section></div>`}
