function updateBudgetAllocation(){const sliders=[...document.querySelectorAll(".allocation-slider")],income=+document.getElementById("income").value||0,goal=+document.getElementById("goalAmount").value||1,values=sliders.map(x=>+x.value),total=values.reduce((a,b)=>a+b,0),remaining=income-total;sliders.forEach((s,i)=>{s.nextElementSibling.textContent=money(values[i]);document.querySelector(`[data-bar="${i}"]`).style.height=`${income?Math.max(2,values[i]/income*100):2}%`});document.getElementById("remaining").textContent=money(remaining);document.getElementById("monthly-target").textContent=money(values[3]);document.getElementById("goal-months").textContent=values[3]?`${Math.ceil(goal/values[3])} mo`:"No target";const status=document.getElementById("budget-status");status.classList.toggle("budget-good",remaining>=0);status.textContent=remaining<0?`Your plan is over budget by ${money(Math.abs(remaining))}. Reduce one or more categories.`:remaining>0?`You still have ${money(remaining)} to assign, save, or keep as a buffer.`:`Every rupee is assigned. Your monthly goal target is ${money(values[3])}.`}
