const FINANCE_KNOWLEDGE={
  "investment banking":["Advanced finance","Investment Banking is a financial service that helps companies, governments, and organizations raise money and complete major financial transactions.","Investment bankers may advise an IPO, acquisition, bond issue, or capital raise."],
  "merger":["Advanced finance","A merger occurs when two companies combine to become one larger company.","Company A and Company B may merge into a single business."],
  "acquisition":["Advanced finance","An acquisition occurs when one company buys another company.","A technology company may acquire a smaller software business."],
  "financial modeling":["Advanced finance","Financial modeling involves building spreadsheets that forecast company performance, including revenue, expenses, profit, and cash flow.","A banker may forecast five years of results before recommending an acquisition."],
  "pitch book":["Advanced finance","A pitch book is a presentation investment bankers use to persuade clients using analysis, valuation, projections, and recommendations.","A pitch book may propose how a company can raise capital or sell itself."],
  "dilution":["Venture capital","Dilution happens when new investors receive shares and existing owners' percentage ownership decreases.","A founder moving from 100% to 80% ownership after funding experiences dilution."],
  "pitch deck":["Venture capital","A pitch deck is a presentation founders use to attract investors by explaining the problem, solution, market, business model, team, and financials.","A startup may show its user growth and funding needs in a pitch deck."],
  "leveraged buyout":["Private equity","A Leveraged Buyout, or LBO, is a company purchase financed with a significant amount of borrowed money.","A PE firm may invest ₹200 crore and borrow ₹800 crore to buy a ₹1,000 crore company."],
  "lbo":["Private equity","LBO means Leveraged Buyout: purchasing a company using a significant amount of debt.","Debt can increase returns but also increases financial risk."],
  "due diligence":["Advanced finance","Due diligence is the detailed analysis of financials, operations, management, competition, and risks before completing an investment or transaction.","A PE firm performs due diligence before buying a company."],
  "capital structure":["Corporate finance","Capital structure is the mix of debt and equity used to finance a company.","A company funded with ₹40 crore debt and ₹60 crore equity has ₹100 crore of capital."],
  "cost of capital":["Corporate finance","Cost of capital is the return required by the providers of a company's debt and equity funding.","A project should generally earn more than its cost of capital to create value."],
  "wacc":["Corporate finance","WACC means Weighted Average Cost of Capital and represents the average cost of a company's funding sources.","If an investment earns 15% while WACC is 10%, it may create value."],
  "capital budgeting":["Corporate finance","Capital budgeting is the process of evaluating major long-term investment projects.","A company may use capital budgeting to decide whether to build a factory."],
  "net present value":["Corporate finance","Net Present Value, or NPV, measures the present value of future cash flows minus the investment required.","A positive NPV generally indicates that a project creates value."],
  "npv":["Corporate finance","NPV means Net Present Value. It measures whether discounted future cash flows exceed the required investment.","Companies use NPV to evaluate major projects."],
  "internal rate of return":["Corporate finance","Internal Rate of Return, or IRR, estimates the return generated by an investment.","A project with an IRR above its required return may be attractive."],
  "irr":["Corporate finance","IRR means Internal Rate of Return, an estimate of an investment project's return.","Companies compare IRR with required returns when selecting projects."],
  "financial markets":["Advanced finance","Financial Markets are places where buyers and sellers exchange financial assets such as stocks, bonds, currencies, commodities, and derivatives.","Markets connect investors with businesses and governments that need capital."],
  "primary market":["Financial markets","A primary market is where new securities are created and sold to investors.","New IPO shares sold by a company are issued in the primary market."],
  "secondary market":["Financial markets","A secondary market is where existing securities trade between investors.","Buying listed shares from another investor is a secondary-market transaction."],
  "price discovery":["Financial markets","Price discovery is the process through which supply and demand determine market prices.","More buyers than sellers can push an asset's price higher."],
  "derivative":["Financial markets","A derivative is a financial contract whose value depends on another asset.","Options, futures, and swaps are derivatives used for hedging, speculation, or risk management."],
  "enterprise value":["Valuation","Enterprise Value represents the value of an entire business and equals Equity Value plus Debt minus Cash.","₹1,000 crore equity value plus ₹300 crore debt minus ₹100 crore cash equals ₹1,200 crore enterprise value."],
  "equity value":["Valuation","Equity Value is the value belonging to shareholders and equals share price multiplied by shares outstanding.","Ten crore shares at ₹100 each create ₹1,000 crore of equity value."],
  "comparable company analysis":["Valuation","Comparable Company Analysis estimates value by comparing a company with similar publicly traded companies.","A company may be valued using the revenue or EBITDA multiples of peers."],
  "precedent transactions":["Valuation","Precedent Transactions analysis uses prices paid in previous acquisitions of similar companies as valuation benchmarks.","If similar businesses sold for 10 times EBITDA, that multiple can inform a valuation."],
  "pre-money valuation":["Venture capital and valuation","Pre-money valuation is a startup's value before a new investment.","A ₹10 crore pre-money valuation plus ₹2 crore investment creates a ₹12 crore post-money valuation."],
  "post-money valuation":["Venture capital and valuation","Post-money valuation is a startup's value after a new investment and equals pre-money valuation plus the investment.","Ownership received commonly equals investment divided by post-money valuation."],
  "accounting equation":["Accounting","The accounting equation is Assets = Liabilities + Equity. It must always balance and forms the foundation of accounting.","A business with ₹15 lakh of assets and ₹5 lakh of liabilities has ₹10 lakh of equity."],
  "general ledger":["Accounting","The General Ledger is the master accounting record containing all individual ledger accounts, including assets, liabilities, equity, revenue, and expenses.","Cash, Sales, Rent, and Inventory accounts all appear in the General Ledger."],
  "double entry":["Accounting","Double-entry accounting records every transaction in at least two accounts, with total debits always equal to total credits.","An owner investment debits Cash and credits Owner's Capital."],
  "debit":["Accounting","A debit is one side of a double-entry accounting record. Its effect depends on the account type, and total debits must equal total credits.","Buying equipment for cash debits Equipment and credits Cash."],
  "credit":["Accounting","A credit is one side of a double-entry accounting record. Its effect depends on the account type, and total credits must equal total debits.","A cash sale debits Cash and credits Sales Revenue."],
  "accounts receivable":["Accounting","Accounts Receivable is money owed to a business by customers who purchased on credit.","A ₹20,000 unpaid customer invoice is Accounts Receivable."],
  "accounts payable":["Accounting","Accounts Payable is money a business owes suppliers for purchases made on credit.","Inventory received today and paid next month creates Accounts Payable."],
  "current asset":["Accounting","A current asset is expected to be converted into cash or used within one year.","Cash, inventory, and accounts receivable are current assets."],
  "non-current asset":["Accounting","A non-current asset provides value for more than one year.","Buildings, machinery, land, and patents are non-current assets."],
  "current liability":["Accounting","A current liability is an obligation due within one year.","Accounts payable, salaries payable, and short-term loans are current liabilities."],
  "non-current liability":["Accounting","A non-current liability is an obligation due after more than one year.","Long-term loans, bonds payable, and mortgages are non-current liabilities."],
  "intangible asset":["Accounting","An intangible asset is a valuable non-physical resource controlled by a business.","Patents, trademarks, software, and brand value can be intangible assets."],
  "retained earnings":["Accounting","Retained Earnings are profits kept within a business rather than distributed as dividends.","Keeping ₹3 lakh of cumulative profit in the company increases equity by ₹3 lakh."],
  "free cash flow":["Accounting and finance","Free Cash Flow is cash remaining after necessary capital investments. It equals Operating Cash Flow minus Capital Expenditures.","₹10 lakh operating cash flow minus ₹3 lakh equipment purchases leaves ₹7 lakh free cash flow."],
  "operating activities":["Accounting","Operating activities are cash flows from a company's core business operations.","Cash received from customers and cash paid to employees are operating activities."],
  "investing activities":["Accounting","Investing activities are cash flows from buying and selling long-term assets and investments.","Purchasing equipment is an investing cash outflow."],
  "financing activities":["Accounting","Financing activities are cash flows from raising or returning capital.","Receiving a loan is a financing inflow; repaying it is a financing outflow."],
  "ledger":["Accounting","A ledger is the main record where a business groups all transactions by account, such as Cash, Sales, or Rent. Journal entries are posted into the ledger, and its balances help prepare financial statements.","A ₹500 cash sale increases the Cash ledger and the Sales ledger by ₹500."],
  "journal entry":["Accounting","A journal entry records a transaction using debits and credits before it is posted to the ledger.","Buying equipment for cash debits Equipment and credits Cash."],
  "trial balance":["Accounting","A trial balance lists every ledger account balance to check whether total debits equal total credits.","If debits and credits differ, an accounting entry may be missing or incorrect."],
  "balance sheet":["Accounting","A balance sheet shows a company's assets, liabilities, and equity at a specific date. The core equation is Assets = Liabilities + Equity.","Cash and equipment are assets; a bank loan is a liability."],
  "income statement":["Accounting","An income statement shows revenue, expenses, and profit over a period. Profit = Revenue - Expenses.","A shop with ₹1,00,000 revenue and ₹70,000 expenses earns ₹30,000 profit."],
  "cash flow statement":["Accounting","A cash flow statement explains cash moving through operating, investing, and financing activities.","Buying machinery is investing cash flow; receiving a bank loan is financing cash flow."],
  "depreciation":["Accounting","Depreciation spreads the cost of a long-term asset across the years it is used. It is an expense but usually not a current cash payment.","A ₹50,000 machine used for five years might record ₹10,000 annual straight-line depreciation."],
  "accrual":["Accounting","Accrual accounting records revenue when earned and expenses when incurred, even if cash moves later.","A December electricity bill paid in January is still a December expense."],
  "ebitda":["Business finance","EBITDA means earnings before interest, taxes, depreciation, and amortization. It is a rough measure of operating performance, but it is not the same as cash flow or profit.","Analysts use EBITDA to compare operations while reducing differences caused by financing and accounting choices."],
  "working capital":["Business finance","Working capital equals current assets minus current liabilities and shows a company's short-term financial flexibility.","Inventory and cash are current assets; bills due soon are current liabilities."],
  "break-even":["Business","The break-even point is where total revenue equals total costs, so profit is zero.","If fixed costs are ₹10,000 and each sale contributes ₹100, the business breaks even after 100 sales."],
  "business model":["Business","A business model explains how a company creates value, delivers it to customers, and earns money.","A subscription app charges customers every month for continued access."],
  "revenue":["Business","Revenue is the total money earned from selling goods or services before expenses are deducted.","Selling 100 items at ₹200 each creates ₹20,000 revenue."],
  "entrepreneurship":["Business","Entrepreneurship is the process of identifying opportunities, creating solutions, and building businesses that provide value to customers.","A student identifies a financial-literacy problem and builds lessons and tools to solve it."],
  "entrepreneur":["Business","An entrepreneur starts and manages a business while taking financial risk in the hope of earning profit and creating value.","Someone launching an app or opening a restaurant is an entrepreneur."],
  "validation":["Business","Validation is testing whether customers actually want a proposed solution before investing major resources.","A founder may interview students or test a simple prototype before building a complete app."],
  "gross revenue":["Business","Gross revenue is total sales before deductions such as returns, discounts, or refunds.","₹10 lakh of sales before refunds is ₹10 lakh gross revenue."],
  "net revenue":["Business","Net revenue is revenue after deductions such as returns, discounts, and refunds.","If gross sales are ₹10 lakh and refunds are ₹1 lakh, net revenue is ₹9 lakh."],
  "gross profit":["Business","Gross profit equals revenue minus cost of goods sold and shows how efficiently products are produced.","₹1,00,000 revenue minus ₹40,000 COGS equals ₹60,000 gross profit."],
  "operating profit":["Business","Operating profit equals gross profit minus operating expenses such as salaries, rent, and marketing.","It measures profit from core business operations before certain non-operating items."],
  "net profit":["Business","Net profit is the final earnings after taxes, interest, and all other expenses.","It is often called the bottom line."],
  "profit margin":["Business","Profit margin measures how much profit remains from each rupee of revenue. Net profit margin = Net profit ÷ Revenue × 100.","₹10 profit on ₹100 revenue is a 10% margin."],
  "expense":["Business","An expense is a cost incurred while operating and generating revenue.","Salaries, rent, raw materials, and marketing are business expenses."],
  "fixed expense":["Business","A fixed expense stays relatively constant even when sales or production change.","Office rent may remain ₹20,000 whether a business sells 10 or 1,000 products."],
  "variable expense":["Business","A variable expense changes with business activity or production volume.","Raw-material and packaging costs rise when more products are made."],
  "cost of goods sold":["Business and accounting","Cost of Goods Sold, or COGS, includes the direct costs of producing goods sold.","Raw materials, direct manufacturing labor, and packaging can be COGS."],
  "burn rate":["Startups","Burn rate is the amount of money a startup spends each month.","A startup spending ₹2 lakh monthly has a ₹2 lakh monthly burn rate."],
  "marketing":["Business","Marketing is the process of understanding customers, creating and communicating value, and attracting sales.","Content, social media, email, and events can connect a useful product with its target audience."],
  "target market":["Business","A target market is the group of customers a business wants to serve.","FinTeen's target market may include teenagers, students, and schools."],
  "marketing funnel":["Business","A marketing funnel describes the customer journey through awareness, interest, consideration, purchase, and loyalty.","A student may discover FinTeen through a video, explore lessons, register, and later recommend it."],
  "four ps":["Business","The Four Ps of marketing are Product, Price, Place, and Promotion.","They help businesses decide what to sell, its price, where to offer it, and how customers discover it."],
  "conversion":["Business","A conversion occurs when someone takes a desired action such as buying, registering, or subscribing.","A website visitor who registers for a workshop creates a conversion."],
  "customer acquisition":["Business","Customer acquisition means gaining new customers, often through advertising, partnerships, or promotions.","Businesses compare acquisition costs with revenue generated by customers."],
  "customer retention":["Business","Customer retention means encouraging existing customers to return and continue using the business.","Strong service and value can improve loyalty and repeat purchases."],
  "value proposition":["Business","A value proposition explains why customers should choose a business, such as better quality, lower prices, or greater convenience.","A clear value proposition connects a customer's problem to the business's solution."],
  "scalability":["Business","Scalability means a business can grow without expenses increasing at the same rate.","Software may serve thousands of additional users without requiring proportional staff growth."],
  "freemium":["Business","A freemium model provides basic features free and charges for advanced features.","A learning app may offer free lessons and charge for premium tutoring."],
  "marketplace business model":["Business","A marketplace connects buyers and sellers and usually earns commissions from transactions.","A platform may earn 10% from a ₹1,000 transaction without owning the product."],
  "minimum viable product":["Startups","A Minimum Viable Product, or MVP, is the simplest product version that solves a problem and enables learning.","A first FinTeen version might contain only lessons, quizzes, and a budget simulator."],
  "mvp":["Startups","MVP means Minimum Viable Product: the simplest product version that solves a problem and tests customer demand.","Founders use MVP feedback before building more features."],
  "product market fit":["Startups","Product-market fit occurs when customers genuinely want a product, shown through strong demand, repeat use, and positive feedback.","Without product-market fit, sustainable startup growth is difficult."],
  "bootstrapping":["Startups","Bootstrapping means building a company using personal funds rather than outside investment.","It preserves ownership and control but limits available resources."],
  "angel investor":["Startups","An angel investor is a wealthy individual who invests capital, advice, and connections in an early-stage startup in exchange for ownership.","Angel investors often support companies before venture-capital funding."],
  "unicorn":["Startups","A unicorn is a startup valued at more than one billion US dollars.","Reaching unicorn status is rare and usually reflects extraordinary expected growth."],
  "startup":["Entrepreneurship","A startup is a young company designed to solve a problem and often grow quickly under uncertainty.","A startup may test a small product first, learn from customers, then scale."],
  "venture capital":["Investing and business","Venture capital is equity funding for young, high-growth companies. Investors accept high risk in exchange for ownership and potential growth.","A VC fund may invest in a technology startup and receive shares."],
  "private equity":["Investing","Private equity firms invest in established private companies, often seeking to improve operations and later sell the investment.","Unlike typical venture capital, private equity usually targets more mature businesses."],
  "valuation":["Corporate finance","Valuation estimates what an asset or company is worth using methods such as discounted cash flow, comparable companies, or precedent transactions.","A DCF estimates today's value of expected future cash flows."],
  "discounted cash flow":["Corporate finance","A discounted cash flow, or DCF, values an investment by estimating future cash flows and discounting them because money today is worth more than money later.","Higher risk normally leads to a higher discount rate and a lower present value."],
  "investment banker":["Corporate finance","An investment banker helps companies raise capital and complete major transactions such as mergers, acquisitions, and public offerings.","They may advise a company selling shares to the public."],
  "stock":["Investing","A stock represents partial ownership in a company. Its price can rise or fall, and returns are never guaranteed.","Owning 1% of a company means owning a small claim on its future results."],
  "shareholder":["Investing","A shareholder is a person or institution that owns shares in a company and therefore owns a small portion of the business.","Shareholders may benefit from dividends, voting rights, or company growth."],
  "ipo":["Investing","IPO means Initial Public Offering. It occurs when a private company sells shares to the public for the first time.","After an IPO, the company becomes publicly traded."],
  "market capitalization":["Investing","Market capitalization measures a company's total stock-market value. It equals share price multiplied by shares outstanding.","A ₹100 share price multiplied by 10,00,000 shares gives a ₹10 crore market cap."],
  "dividend":["Investing","A dividend is a distribution of part of a company's profits to shareholders.","A profitable company may pay cash dividends while keeping the remaining profit for growth."],
  "capital appreciation":["Investing","Capital appreciation is an increase in an asset's price or value over time.","Buying at ₹100 and later selling at ₹150 creates ₹50 of capital appreciation per share."],
  "bond":["Investing","A bond is a loan made by an investor to a company or government. The borrower promises interest and repayment, but credit risk still exists.","A government bond may pay fixed interest until maturity."],
  "coupon rate":["Investing","A bond's coupon rate is the interest rate paid based on its face value.","An 8% coupon on a ₹10,000 face-value bond pays ₹800 annually."],
  "maturity date":["Investing","A bond's maturity date is when the borrower is scheduled to repay the principal.","A bond issued in 2025 with a 2030 maturity returns principal in 2030, assuming no default."],
  "bond yield":["Investing","Bond yield measures the return generated by a bond. It may differ from the coupon rate because bond prices can change.","When a bond trades below face value, its yield may be higher than its coupon rate."],
  "default risk":["Investing","Default risk is the possibility that a borrower will fail to pay interest or repay principal.","Lower-rated corporate bonds usually carry more default risk than high-quality government bonds."],
  "etf":["Investing","An ETF is a fund traded on an exchange that can hold many assets. It can provide diversification, but its value can still fall.","A broad-market ETF may hold shares in hundreds of companies."],
  "index":["Investing","An index is a group of securities used to measure market performance, like a scorecard.","The Nifty 50 tracks 50 major Indian companies."],
  "expense ratio":["Investing","An expense ratio is the annual fee charged by a fund to cover management and operating costs.","Lower expenses generally allow investors to keep more of the fund's returns."],
  "passive investing":["Investing","Passive investing aims to match the performance of an index rather than actively select assets to beat it.","A Nifty 50 index fund tries to track the Nifty 50."],
  "mutual fund":["Investing","A mutual fund pools money from many investors and is managed according to a stated strategy.","Its fees, risks, and holdings should be understood before investing."],
  "nav":["Investing","NAV means Net Asset Value and represents the value of one mutual fund unit. NAV equals total asset value divided by total units.","A ₹100 crore fund with 10 crore units has an NAV of ₹10."],
  "sip":["Investing","SIP means Systematic Investment Plan. It is a method of investing a fixed amount into a mutual fund at regular intervals.","Investing ₹2,000 every month is a monthly SIP."],
  "rupee cost averaging":["Investing","Rupee cost averaging occurs when regular fixed investments buy more units at low prices and fewer units at high prices.","A ₹1,000 SIP buys 100 units at ₹10 NAV but only 40 units at ₹25 NAV."],
  "risk tolerance":["Investing","Risk tolerance is the amount of uncertainty and potential loss an investor is comfortable accepting.","Goals, age, financial situation, and personality can affect risk tolerance."],
  "volatility":["Investing","Volatility measures how much an investment's price moves. Larger movements generally indicate greater uncertainty.","A stock moving between ₹100 and ₹150 is more volatile than one moving between ₹100 and ₹105."],
  "liquidity risk":["Investing","Liquidity risk is the risk that an asset cannot be converted into cash quickly without a significant price reduction.","An asset with few buyers may be difficult to sell at a fair price."],
  "diversification":["Investing","Diversification means spreading exposure across different assets so one poor result has less impact. It reduces some risk but cannot eliminate all risk.","Holding many sectors is generally more diversified than holding one company."],
  "systematic risk":["Investing","Systematic risk affects broad markets and cannot be eliminated through diversification.","Recessions and major financial crises can affect most investments."],
  "unsystematic risk":["Investing","Unsystematic risk is specific to a company or industry and can be reduced through diversification.","A product failure at one company is an unsystematic risk."],
  "correlation":["Investing","Correlation measures how investments move relative to each other. Combining assets with different correlations can improve diversification.","If one asset rises when another falls, they have negative correlation."],
  "compound interest":["Personal finance","Compound interest means earning growth on both the original amount and earlier growth.","₹1,000 growing 10% becomes ₹1,100, then ₹1,210."],
  "rule of 72":["Investing","The Rule of 72 estimates how many years money may take to double. Divide 72 by the annual interest rate.","At 8%, money approximately doubles in 9 years because 72 ÷ 8 = 9."],
  "inflation":["Economics","Inflation is a general rise in prices over time that reduces purchasing power.","If a ₹50 snack rises to ₹55, the same ₹50 buys less."],
  "gdp":["Economics","GDP is the total market value of final goods and services produced within a country during a period.","GDP growth can indicate expanding production, but it does not measure every part of well-being."],
  "monetary policy":["Economics","Monetary policy is how a central bank influences inflation and economic activity, often through interest rates and money supply.","Raising policy rates can reduce borrowing and demand."],
  "fiscal policy":["Economics","Fiscal policy is the government's use of spending and taxation to influence the economy.","Higher infrastructure spending can support demand and employment."],
  "recession":["Economics","A recession is a significant, broad decline in economic activity lasting more than a brief period.","Businesses may sell less, unemployment may rise, and investment may slow."],
  "exchange rate":["Economics","An exchange rate states how much one currency is worth in another currency.","If 1 USD equals ₹85, then 10 USD equals ₹850."],
  "bank":["Banking","A bank accepts deposits, facilitates payments, and lends money while managing risk and following regulation.","Banks connect savers with borrowers."],
  "upi":["Banking and payments","UPI is India's real-time bank-to-bank payment system developed by NPCI.","A user can scan a QR code and transfer money within seconds."],
  "credit score":["Personal finance","A credit score summarizes a borrower's credit history and repayment behavior. Lenders may use it when judging risk.","Paying obligations on time generally supports a healthier credit history."],
  "budget":["Personal finance","A budget is a plan for income, spending, saving, and goals.","A student can assign money to needs first, then savings and wants."],
  "needs vs wants":["Personal finance","Needs are essential for basic functioning, while wants improve comfort or enjoyment. Context matters, but needs should generally be prioritized first.","A functional laptop for school may be a need; a premium upgrade may be a want."],
  "opportunity cost":["Economics and personal finance","Opportunity cost is the value of the best alternative you give up when making a choice.","Spending ₹2,000 on shoes means giving up the chance to save or use that ₹2,000 for another goal."],
  "present bias":["Behavioral finance","Present bias is the tendency to prefer a smaller reward now over a larger future benefit.","Spending all pocket money today instead of saving for a laptop shows present bias."],
  "pay yourself first":["Personal finance","Pay yourself first means moving money into savings immediately when income arrives, before spending the rest.","Receive ₹2,000, save ₹500 first, then plan how to spend ₹1,500."],
  "emergency fund":["Personal finance","An emergency fund is money reserved for unexpected necessary costs, helping avoid high-cost debt.","It could cover an urgent repair or medical expense."],
  "financial goal":["Personal finance","A financial goal is a specific money-related objective with a target and plan. Strong goals are often SMART: Specific, Measurable, Achievable, Relevant, and Time-Bound.","Save ₹2,000 each month for ten months to buy a ₹20,000 laptop."],
  "smart goal":["Personal finance","A SMART financial goal is Specific, Measurable, Achievable, Relevant, and Time-Bound.","Instead of saying 'I want money,' define a rupee target, monthly action, and deadline."],
  "smart spending":["Personal finance","Smart spending means making thoughtful purchases that provide strong value and support your priorities.","Researching a durable product and comparing alternatives is smarter than buying only because of a sale."],
  "cost per use":["Personal finance","Cost per use equals an item's price divided by how many times it is used. It helps compare value, not just price.","A ₹2,000 bat used 200 times costs ₹10 per use."],
  "lifestyle inflation":["Personal finance","Lifestyle inflation happens when spending rises whenever income rises, preventing extra income from improving savings.","After a raise, upgrading every subscription and purchase can consume all the added income."],
  "impulse purchase":["Behavioral finance","An impulse purchase is an unplanned purchase driven by a temporary feeling rather than careful consideration.","A countdown sale may create urgency to buy something you did not plan to purchase."],
  "delayed gratification":["Behavioral finance","Delayed gratification means giving up a smaller immediate reward to achieve a larger future reward.","Skipping frequent small purchases can help reach a laptop savings goal sooner."],
  "emotional spending":["Behavioral finance","Emotional spending occurs when feelings such as stress, boredom, or excitement drive purchases.","Buying something to feel better may provide short relief but delay financial goals."],
  "tax":["Public finance","A tax is a compulsory payment collected by government to fund public services and policy goals.","Income tax and goods-and-services taxes are different forms of taxation."],
  "capital":["Finance","Capital is money or other resources used to create future value.","A business may use capital to buy equipment, hire employees, or develop products."],
  "asset":["Accounting and finance","An asset is a resource expected to provide future economic benefit.","Cash, inventory, equipment, and certain investments can be assets."],
  "liability":["Accounting and finance","A liability is an obligation owed to another party.","Loans, unpaid bills, and certain taxes payable are liabilities."],
  "equity":["Accounting and finance","Equity is the owners' residual interest after liabilities are subtracted from assets.","If assets are ₹10 lakh and liabilities are ₹6 lakh, equity is ₹4 lakh."]
};
function tutorReply(t){const q=t.toLowerCase().replace(/[?.,-]/g," "),career=FINANCE_CAREERS.find(c=>q.includes(c.name.toLowerCase())||q.includes(c.name.toLowerCase().replace(/\s*\(.+?\)/,""))),careerTopic=["career","job","salary","certification","university","college","skills","responsibilities","pathway"].some(x=>q.includes(x));if(career){return `<strong>${career.name}</strong><br><br><strong>Career overview:</strong> ${career.definition}<br><br><strong>What the work involves:</strong> ${career.tasks.join("; ")}.<br><br><strong>Salary:</strong> In India, typical ranges progress from ${career.india.join(" to ")}. In the United States, ranges progress from ${career.usa.join(" to ")}. Actual compensation varies by location, firm, and performance.<br><br><strong>Relevant skills:</strong> ${career.skills.join(", ")}.<br><br><strong>Education and progression:</strong> ${career.roadmap.join(" → ")}. Helpful majors include ${career.majors.join(", ")}, while useful certifications include ${career.certifications.join(", ")}.<br><br><strong>Benefits:</strong> Strong learning, meaningful business exposure, and attractive long-term career opportunities.<br><br><strong>Challenges:</strong> Difficulty is ${career.difficulty}/10, so students should expect competition, demanding skill development, and responsibility.<br><br><strong>Personality match:</strong> This career often suits students who ${career.fit.join(", ").toLowerCase()}.`}const keys=Object.keys(FINANCE_KNOWLEDGE).sort((a,b)=>b.length-a.length),key=keys.find(k=>q.includes(k));if(key){const [area,definition,example]=FINANCE_KNOWLEDGE[key],related=FINANCE_CAREERS.filter(c=>c.skills.some(s=>s.toLowerCase().includes(key))||c.definition.toLowerCase().includes(key)).slice(0,3).map(c=>c.name);return `<strong>${key.replace(/\b\w/g,c=>c.toUpperCase())}</strong> · ${area}<br><br><strong>Explanation:</strong> ${definition}<br><br><strong>Real-world example:</strong> ${example}<br><br><strong>Benefits and uses:</strong> Understanding this concept improves financial decision-making, helps people compare alternatives, and makes risks and trade-offs easier to identify.<br><br><strong>Challenges:</strong> The concept must be applied with accurate information and context; oversimplifying it can lead to poor decisions.${related.length?`<br><br><strong>Career opportunities:</strong> This knowledge is especially useful in ${related.join(", ")}.`:""}<br><br><strong>Critical-thinking check:</strong> What assumptions could change the outcome in a real situation?`}if(careerTopic){return `<strong>Finance career guidance</strong><br><br>FinTeen Career Explorer covers ${FINANCE_CAREERS.map(c=>c.name).join(", ")}.<br><br>For each career, I can explain responsibilities, salaries, difficulty, required skills, certifications, college majors, university pathways, internships, personality fit, and career progression. Ask about a specific career for a detailed answer.`}const stop=new Set(["what","why","how","does","is","are","the","a","an","of","in","to","and","for","explain","tell","about","me"]),terms=q.split(/\s+/).filter(x=>x.length>3&&!stop.has(x)),paragraphs=[...LESSON_MARKDOWN,...PERSONAL_FINANCE_MARKDOWN,...INVESTING_MARKDOWN,...BUSINESS_MARKDOWN,...ACCOUNTING_MARKDOWN,...ADVANCED_FINANCE_MARKDOWN].flatMap(doc=>doc.split(/\n\n+/).map(p=>({p,score:terms.reduce((n,w)=>n+(p.toLowerCase().includes(w)?1:0),0)}))).filter(x=>x.score>0).sort((a,b)=>b.score-a.score);if(paragraphs[0]?.score>=Math.max(1,Math.min(2,terms.length))){const best=paragraphs.slice(0,4).map(x=>x.p.replace(/^#+\s*/,"").replace(/\*\*/g,"")).join("<br><br>");return `<strong>Explanation from the FinTeen lesson library:</strong><br><br>${best}<br><br><strong>Why it matters:</strong> This concept affects how people, businesses, or markets make decisions and manage risk.<br><br><strong>Practical application:</strong> Compare the choices available, calculate the financial effect, and identify the trade-offs before deciding.<br><br><strong>Critical-thinking check:</strong> What could go wrong, and what information would improve the decision?`}const financeWords=["finance","financial","account","econom","business","bank","invest","money","market","company","corporate","fund","capital","cash","credit","debit","loan","interest","wealth","currency","payment","trade","tax","insurance","entrepreneur","profit","cost","price","income","expense","saving","portfolio","audit","commerce","budget","spending","goal","startup","marketing","revenue","career","salary"];if(!financeWords.some(x=>q.includes(x)))return "Sorry, but your question is not related to finance or finance careers.";return `<strong>Let’s analyze this finance question.</strong><br><br><strong>Explanation:</strong> Start by defining the concept and identifying how money, value, risk, or ownership moves.<br><br><strong>Real-world application:</strong> Consider who makes the decision, what they gain, what they give up, and what could change the result.<br><br><strong>Benefits and challenges:</strong> Financial choices can create growth and opportunity, but uncertainty, incomplete information, and risk must always be considered.<br><br>Please name the specific concept or career you want to explore, and I will give you a detailed lesson-based explanation.`}
function renderQuiz(){const item=currentQuiz()[quizIndex],doc=getActiveDoc();return `<div class="quiz-wrap">${pageHead(item.level,doc?.title||"Lesson quiz","12 questions based entirely on the lesson you completed.")}<div class="quiz-progress"><div class="progress-track"><div class="progress-fill" style="width:${(quizIndex+1)/12*100}%"></div></div><span>${quizIndex+1} of 12</span></div><section class="card quiz-card"><span class="question-tag">${item.level}</span><h2>${item.q}</h2><div class="answer-list">${item.options.map((x,i)=>`<button class="answer" data-answer="${i}">${String.fromCharCode(65+i)}. ${x}</button>`).join("")}</div><div class="quiz-feedback hidden" id="quiz-feedback"></div><button class="button primary hidden" id="next-question" style="margin-top:16px">${quizIndex===11?"Finish quiz":"Next question"} →</button></section></div>`}
function navigate(view){currentView=view;title.textContent=({dashboard:"Overview",learn:"Learning Center",simulator:"Budget Lab",tutor:"AI Tutor",careers:"Career Explorer",quiz:"Quiz"})[view];document.querySelectorAll(".nav-item").forEach(x=>x.classList.toggle("active",x.dataset.view===view));container.innerHTML=({dashboard:renderDashboard,learn:renderLearn,simulator:renderSimulator,tutor:renderTutor,careers:renderCareers,quiz:renderQuiz})[view]();bind();window.scrollTo({top:0,behavior:"smooth"})}
function bind(){document.querySelectorAll("[data-view]").forEach(x=>x.onclick=e=>{e.preventDefault();activeModule=activeLesson=activeCareer=null;navigate(x.dataset.view);document.querySelector(".sidebar").classList.remove("open")});document.querySelectorAll("[data-career]").forEach(x=>x.onclick=()=>{activeCareer=+x.dataset.career;navigate("careers")});document.getElementById("back-careers")?.addEventListener("click",()=>{activeCareer=null;navigate("careers")});document.querySelectorAll("[data-module]").forEach(x=>x.onclick=()=>{activeModule=+x.dataset.module;activeLesson=null;navigate("learn")});document.querySelectorAll("[data-lesson]").forEach(x=>x.onclick=()=>{activeLesson=+x.dataset.lesson;navigate("learn")});document.querySelectorAll("[data-quiz]").forEach(x=>x.onclick=()=>{activeLesson=+x.dataset.quiz;quizIndex=quizScore=0;navigate("quiz")});document.getElementById("back-modules")?.addEventListener("click",()=>{activeModule=null;navigate("learn")});["back-lessons","back-lessons-2"].forEach(id=>document.getElementById(id)?.addEventListener("click",()=>{activeLesson=null;navigate("learn")}));document.getElementById("complete-lesson")?.addEventListener("click",()=>{const id=`${activeModule}-${activeLesson}`;if(!state.completedLessons.includes(id)){state.completedLessons.push(id);save();syncUser()}navigate("learn")});document.querySelectorAll(".goal-pill").forEach(x=>x.onclick=()=>{document.querySelectorAll(".goal-pill").forEach(p=>p.classList.remove("active"));x.classList.add("active");document.querySelector(".custom-goal").classList.toggle("show",x.textContent==="Custom Goal")});document.getElementById("run-sim")?.addEventListener("click",runSimulator);document.querySelectorAll(".allocation-slider").forEach(x=>x.oninput=updateBudgetAllocation);document.querySelectorAll(".prompt").forEach(x=>x.onclick=()=>{document.getElementById("chat-text").value=x.textContent;document.getElementById("chat-form").requestSubmit()});document.getElementById("chat-form")?.addEventListener("submit",e=>{e.preventDefault();const i=document.getElementById("chat-text"),m=document.getElementById("messages");if(!i.value.trim())return;m.insertAdjacentHTML("beforeend",`<div class="message user">${i.value}</div><div class="message">${tutorReply(i.value)}</div>`);i.value="";m.scrollTop=m.scrollHeight});document.querySelectorAll("[data-answer]").forEach(x=>x.onclick=()=>{const chosen=+x.dataset.answer,item=currentQuiz()[quizIndex];if(chosen===item.answer)quizScore++;document.querySelectorAll(".answer").forEach((a,i)=>{a.disabled=true;if(i===item.answer)a.classList.add("correct")});if(chosen!==item.answer)x.classList.add("wrong");document.getElementById("quiz-feedback").innerHTML=`<strong>${chosen===item.answer?"Correct.":"Not quite."}</strong> ${item.why}`;document.getElementById("quiz-feedback").classList.remove("hidden");document.getElementById("next-question").classList.remove("hidden")});document.getElementById("next-question")?.addEventListener("click",()=>{if(quizIndex<11){quizIndex++;navigate("quiz")}else{state.quizzes.push({lesson:`${activeModule}-${activeLesson}`,score:quizScore});save();syncUser();quizIndex=quizScore=0;activeLesson=null;navigate("dashboard")}})}
document.querySelector(".mobile-menu").onclick=()=>document.querySelector(".sidebar").classList.toggle("open");
document.querySelector(".sidebar-footer button").onclick=toggleAccountMenu;
document.getElementById("learner-count").onclick=()=>{document.getElementById("learner-count").title=`${learnerCount.toLocaleString("en-IN")} successful sign-ins so far`};
syncUser();if(state.user)navigate("dashboard");else onboarding();
